import React from 'react';
import ProjectList from './components/ProjectList';

const navLinks = [
  "All Projects",
  "Selected Work",
  "Narrative",
  "Music Videos",
  "Commercials",
  "Format Agnostic"
];

const App = () => (
  <div className="min-h-screen bg-black text-white font-mono">
    <header className="flex justify-between items-start px-8 pt-8">
      <nav>
        <div className="mb-4">ARCHIVE</div>
        <ul className="space-y-1 text-gray-400 text-sm tracking-widest">
          {navLinks.map(link => (
            <li key={link}>{link.toUpperCase()}</li>
          ))}
        </ul>
      </nav>
      <h1 className="font-serif text-white text-7xl text-center flex-1 tracking-wide">
        MIGUEL VERDUZCO
      </h1>
      <div className="text-gray-400 text-sm tracking-widest mt-2">INFORMATION</div>
    </header>
    <main className="px-8 pt-16">
      <ProjectList />
    </main>
  </div>
);

export default App;
